mapper.select:
SELECT COUNT(*)
FROM user_group_relations
WHERE user_id = #{userId}
AND group_id = #{groupId}
AND is_deleted = 0

SELECT *
FROM user_group_relations
WHERE user_id = #{userId}
AND group_id = #{groupId}
LIMIT 1

mapper.update:
UPDATE user_group_relations
SET is_deleted = 1,
    updated_at = NOW()
WHERE user_id = #{userId}
AND group_id = #{groupId}

UPDATE user_group_relations
SET is_deleted = 0,
    updated_at = NOW()
WHERE user_id = #{userId}
AND group_id = #{groupId}
